import React from "react";

import { CloseIcon, RefreshIcon, WarningIcon } from "@steez-ui/icons";

import buttonStyles from "../styles/Buttons.module.css";
import styles from "./ErrorMessage.module.css";

export interface ErrorMessageProps {
  title?: string;
  message: string;
  details?: string;
  onRetry?: () => void;
  onDismiss?: () => void;
  variant?: "inline" | "card" | "fullScreen";
}

export const ErrorMessage = React.memo(function ErrorMessage({
  title = "Error",
  message,
  details,
  onRetry,
  onDismiss,
  variant = "card",
}: ErrorMessageProps) {
  const content = (
    <>
      <div className={styles.header}>
        <WarningIcon width={24} height={24} />
        <h3>{title}</h3>
      </div>
      <p className={styles.message}>{message}</p>
      {details ? (
        <details className={styles.details}>
          <summary>Details</summary>
          <pre>{details}</pre>
        </details>
      ) : null}
      {onRetry || onDismiss ? (
        <div className={styles.actions}>
          {onRetry ? (
            <button type="button" onClick={onRetry} className={buttonStyles.secondary}>
              <RefreshIcon width={16} height={16} />
              {" "}
              Try Again
            </button>
          ) : null}
          {onDismiss ? (
            <button type="button" onClick={onDismiss} className={buttonStyles.secondary}>
              <CloseIcon width={16} height={16} />
              {" "}
              Dismiss
            </button>
          ) : null}
        </div>
      ) : null}
    </>
  );

  if (variant === "fullScreen") {
    return (
      <div className={styles.fullScreen} role="alert" aria-live="assertive">
        <div className={styles.card}>{content}</div>
      </div>
    );
  }

  if (variant === "inline") {
    return (
      <div className={styles.inline} role="alert" aria-live="assertive">
        {content}
      </div>
    );
  }

  return (
    <div className={styles.card} role="alert" aria-live="assertive">
      {content}
    </div>
  );
});

.card {
  background: color-mix(in srgb, var(--bg-secondary) 90%, transparent);
  border: 1px solid var(--danger);
  border-radius: var(--radius-md);
  padding: 1.5rem;
  margin: 1rem 0;
}

.inline {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  padding: 1rem;
  background: var(--danger-bg);
  border-left: 4px solid var(--danger);
  margin: 0.5rem 0;
}

.fullScreen {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(1, 6, 7, 0.8);
  z-index: 999;
}

.header {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: var(--danger);
  margin-bottom: 0.5rem;
}

.header h3 {
  margin: 0;
  font-size: 1.1rem;
}

.message {
  color: var(--text-primary);
  margin: 0 0 1rem 0;
  line-height: 1.5;
}

.details {
  margin: 1rem 0;
  padding: 0.5rem;
  background: var(--bg-primary);
  border-radius: var(--radius-sm);
  font-size: 0.85rem;
}

.details summary {
  cursor: pointer;
  color: var(--text-secondary);
  margin-bottom: 0.5rem;
}

.details pre {
  margin: 0;
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-word;
  color: var(--text-secondary);
}

.actions {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.primary {
  padding: 8px 16px;
  background: var(--interactive-primary-bg);
  color: var(--interactive-primary-fg);
  border: 1px solid var(--interactive-primary-border);
  border-radius: 6px;
  cursor: pointer;
  transition: all var(--transition-fast);
  font-family: var(--font-mono);
  font-weight: 600;
  font-size: 0.875rem;
}

.primary:hover:not(:disabled) {
  background: var(--interactive-primary-bg-hover);
  border-color: var(--interactive-primary-border);
}

.secondary {
  padding: 8px 16px;
  background: var(--interactive-secondary-bg);
  color: var(--interactive-secondary-fg);
  border: 1px solid var(--interactive-secondary-border);
  border-radius: 6px;
  cursor: pointer;
  transition: all var(--transition-fast);
  font-family: var(--font-mono);
  font-weight: 600;
  font-size: 0.875rem;
}

.secondary:hover:not(:disabled) {
  color: var(--interactive-secondary-fg);
  background: var(--interactive-secondary-bg-hover);
  border-color: var(--interactive-secondary-border-hover);
}

.toolbarButton {
  display: inline-flex;
  align-items: center;
  gap: 0.375rem;
  padding: 0.5rem 0.75rem;
  background: var(--interactive-secondary-bg);
  color: var(--interactive-secondary-fg);
  border: 1px solid var(--interactive-secondary-border);
  border-radius: 4px;
  cursor: pointer;
  transition: all var(--transition-fast);
  font-family: var(--font-mono);
  font-size: 0.875rem;
  font-weight: 500;
  white-space: nowrap;
}

.toolbarButton:hover:not(:disabled) {
  background: var(--interactive-primary-bg);
  border-color: var(--interactive-primary-border);
  color: var(--interactive-primary-fg);
}

.danger {
  padding: 8px 16px;
  background: var(--danger-bg);
  color: var(--danger);
  border: 1px solid var(--danger);
  border-radius: 6px;
  cursor: pointer;
  transition: all var(--transition-fast);
  font-family: var(--font-mono);
  font-weight: 600;
  font-size: 0.875rem;
}

.danger:hover:not(:disabled) {
  background: var(--danger);
  color: var(--text-on-accent);
}

.small {
  padding: 4px 10px;
  font-size: 0.75rem;
}

.large {
  padding: 12px 24px;
  font-size: 1rem;
}

.primary:disabled,
.secondary:disabled,
.toolbarButton:disabled,
.danger:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}
